import ListAndAddNotes from './components/ListAndAddNotes.vue';

export default {
    name: "InvoiceAdd",
    components: {
        LineItems,
        EditInvoiceLineItem,
        AdvanceFilter,
        ChangeClientAndUtility,
        ManageWorkCode,
        AddDiscount,
        SearchableSelect,
        Pager,
        ManageColumnItems,
        BulkInsertWorkCode,
        ListAndAddNotes
    },
    data() {
        return {
            columnValueInputVisible: true,
            columnValueInputClasses: 'form-control width_100',
            columnValueInputMaxlength: null,
            columnValueInputReadonly: false,
            columnValueInputPlaceholder: '',
            isLoading: false,
            billId: 0,
            UserId: '',
            batchId: null,
            lineBatchId: null,
            refreshKey: 0,
            setupId: 32,
            showMainForm: false,
            invoiceStatus: 'NotShowNumber',
