        onSearch() {
            
            var vm = this;
            vm.isLoading = true;
            vm.validationErrors = {
                ClientId: '',
                DivisionId: '',
                dateFrom: '',
                dateTo: ''
            };

            var hasError = false;

            // Validate Client
            if (!vm.searchData.ClientId || vm.searchData.ClientId === '0' || vm.searchData.ClientId === '') {
                vm.validationErrors.ClientId = vm.$t('ClientRequired');
                hasError = true;
            }

            // Validate Division
            if (!vm.searchData.DivisionId || vm.searchData.DivisionId === '') {
                vm.validationErrors.DivisionId = vm.$t('DivisionRequired');
                hasError = true;
            }

            // Validate Date From
            if (!vm.searchData.dateFrom || vm.searchData.dateFrom === '') {
                vm.validationErrors.dateFrom = vm.$t('DateFromRequired');
                hasError = true;
            } else {
                // Validate date format
                // if (!vm.validateDate(vm.searchData.dateFrom)) {
                //     vm.validationErrors.dateFrom = vm.$t('InvalidDateFormat');
                //     hasError = true;
                // }
            }

            // Validate Date To
            if (!vm.searchData.dateTo || vm.searchData.dateTo === '') {
                vm.validationErrors.dateTo = vm.$t('DateToRequired');
                hasError = true;
            } else {
                // Validate date format
                // if (!vm.validateDate(vm.searchData.dateTo)) {
                //     vm.validationErrors.dateTo = vm.$t('InvalidDateFormat');
                //     hasError = true;
                // }
            }

            // Check if setup exists
            if (!vm.setupId || vm.setupId === "" || vm.setupId === null) {
                alert(vm.$t('SetupNotExistClient'));
                vm.isLoading = false;
                return;
            }

            if (hasError) {
                vm.isLoading = false;
                return;
            }

            // Set Bill Issue Date to dateTo
            vm.invoiceData.BillIssueDate = vm.searchData.dateTo;

            // Calculate due date (30 days from issue date)
            var issueDate = new Date(vm.searchData.dateTo);
            var dueDate = new Date(issueDate);
            dueDate.setDate(dueDate.getDate() + 30);
            vm.invoiceData.BillDueDate = vm.formatDate(dueDate);

            try {
                // Load company dropdown with parent-child client list
                vm.showCompanyClientsDropDown(vm.searchData.ClientId);

                // Load Payment Terms if applicable
                if (vm.paymentTermAllowed === 'yes') {
                    vm.loadPaymentTerms(vm.searchData.ClientId);
                }

                // Load Project List
                vm.loadProjectList(vm.searchData.ClientId);

                // Set invoice data from search
                vm.invoiceData.ClientId = vm.searchData.ClientId;
                vm.invoiceData.DivisionId = vm.searchData.DivisionId;
                vm.invoiceData.DateRangeFrom = vm.searchData.dateFrom;
                vm.invoiceData.DateRangeTo = vm.searchData.dateTo;

                // Get selected division details
                var selectedDivision = vm.divisionList.find(d => d.ID == vm.searchData.DivisionId);
                if (selectedDivision) {
                    vm.invoiceData.DivisionId = selectedDivision.ID;
                    vm.invoiceData.DivisionName = selectedDivision.NOTE || selectedDivision.text;
                    vm.invoiceData.NoOfNotes = selectedDivision.NO_OF_NOTES || 0;
                    vm.searchData.NoOfNotes = selectedDivision.NO_OF_NOTES || 0;

                    // Set template and other details if creating new invoice
                    if (vm.billId <= 0) {
                        vm.invoiceData.DetailFileFormat = selectedDivision.DETAIL_FORMAT_TYPE;
                        var previousTemplateId = vm.invoiceData.TemplateId;
                        vm.invoiceData.TemplateId = selectedDivision.INVOICE_DETAIL_TEMPLATE;
                        vm.invoiceData.InvoiceTypeId = selectedDivision.INVOICE_TYPE_ID;
                        vm.invoiceData.ProjectId = selectedDivision.PROJECT_ID;

                        // Load filter fields if template changed
                        if (vm.invoiceData.TemplateId && vm.invoiceData.TemplateId !== previousTemplateId) {
                            vm.$nextTick(function () {
                                vm.loadFilterFields();
                            });
                        }
                    }
