                parentData.forEach(function (parent) {
                    // Add parent company
                    companyListData.push({
                        Value: parent.value,
                        Text: parent.text,
                        IsParent: true
                    });
                    // Get child companies for this parent
                    var childData = data.filter(function (val) {
                        return val.firstAttribute === parent.value;
                    });
                    // Add child companies
                    childData.forEach(function (child) {
                        companyListData.push({
                            Value: child.value,
                            Text: '  ' + child.text, // Indent child items
                            IsParent: false,
                            ParentId: parent.value
                        });
                    });
                });

                vm.companyList = companyListData;
                // Set default selection to first company (0 index)
                if (vm.companyList.length > 0) {
                    vm.invoiceData.ParentCompanyId = vm.companyList[0].Value;
