        loadLineItems() {
            debugger;
            var vm = this;
            vm.$set(vm, 'isLoading', true);
            // Validate required parameters
            var clientId = vm.invoiceData.ClientId || vm.searchData.ClientId;
            if (!clientId || clientId === 0 || clientId === '0' || clientId === '') {
                console.warn('ClientId is required for loading line items');
                vm.$set(vm, 'isLoading', false);
                return;
            }

            if (!vm.setupId || vm.setupId === 0) {
                console.warn('SetupId is required for loading line items');
                vm.$set(vm, 'isLoading', false);
                return;
            }

            // Build filter XML from active filters if they exist
            if (vm.activeFilters && vm.activeFilters.length > 0) {
                vm.buildFilterXml();
            } else {
                vm.filterXmlData = '';
            }

            // Build query parameters for FetchLineItems API
            var params = [];

            // Required and optional parameters
            if (vm.billId) params.push(`billId=${vm.billId}`);

            // Required: clientId and setupId
            params.push(`clientId=${clientId}`);
            params.push(`setupId=${vm.setupId}`);

            var divisionId = vm.invoiceData.DivisionId || vm.searchData.DivisionId;
            if (divisionId) params.push(`divisionId=${divisionId}`);

            if (vm.invoiceData.TemplateId) params.push(`templateId=${vm.invoiceData.TemplateId}`);
            var dateFrom = vm.invoiceData.DateRangeFrom || vm.searchData.dateFrom;
            var dateTo = vm.invoiceData.DateRangeTo || vm.searchData.dateTo;

            if (dateFrom) {
                var dateFromFormatted = vm.$options.filters.formatDateYYMMDD(dateFrom);
                if (dateFromFormatted) {
                    params.push(`dateFrom=${encodeURIComponent(dateFromFormatted)}`);
                } else {
                    console.warn('Invalid dateFrom format:', dateFrom);
                }
            }

            if (dateTo) {
                var dateToFormatted = vm.$options.filters.formatDateYYMMDD(dateTo);
                if (dateToFormatted) {
                    params.push(`dateTo=${encodeURIComponent(dateToFormatted)}`);
                } else {
                    console.warn('Invalid dateTo format:', dateTo);
                }
            }
            var offset = ((vm.currentPage - 1)) + 1;
            params.push(`offset=${offset}`);
            params.push(`fetchNext=${vm.pageSize}`);
            if (vm.batchId) params.push(`batchId=${vm.batchId}`);
            params.push(`requestFrom=INVOICEEDITMODE`);
            if (vm.lineBatchId) params.push(`lineBatchId=${vm.lineBatchId}`);
            params.push(`sortBy=${vm.sortBy || '1'}`);
            params.push(`sortExp=${vm.sortExp || 'Asc'}`);
            var dbCondition = vm.databaseCondition ? vm.databaseCondition.trim() : '';

            if (dbCondition && dbCondition.length > 0) {
                var encodedCondition = encodeURIComponent(dbCondition);
                params.push(`databaseCondition=${encodedCondition}`);
                console.log('✓ Adding databaseCondition to URL:', dbCondition);
                console.log('✓ Encoded databaseCondition:', encodedCondition);
            } else if (vm.filterXmlData && vm.filterXmlData.trim().length > 0) {
                params.push(`xmlData=${encodeURIComponent(vm.filterXmlData)}`);
                console.log('Using filterXmlData instead of databaseCondition');
            } else {
                console.log('No databaseCondition or filterXmlData to add');
            }

            var url = params.join('&');
            return locateBillingService.LoadLineItems(url).then((response) => {
                console.log('Line items response:', response);
                if (response && response.data) {
                    var data = response.data;

                    // Handle response structure - API returns camelCase: lineItems, totalRecords, etc.
                    if (data.lineItems || data.LineItems) {
                        // Use camelCase first, fallback to PascalCase for compatibility
                        var lineItems = data.lineItems || data.LineItems || [];

                        // Use Vue.set for reactivity
                        vm.$set(vm, 'lineItemsData', lineItems);
                        var nonVisibleInSummaryCol8Sum = 0;
                        vm.lineItemsData.forEach(item => {
                            var isSelected = false;
                            if (vm.selectAllInvoice === '1') {
                                // If select all is active, mark selectable items as selected
                                isSelected = item.ticketType !== 'F' && item.isManual !== true;
                            }
                            // else if (vm.selectedLineItemIds != '' && vm.selectedLineItemIds.length != 0) {
                            //     // Check if this item is in the selected list
                            //     var itemId = String(item.lineItemId || item.LineItemId);
                            //     isSelected = vm.selectedLineItemIds.split(',').includes(itemId);
                            // }
                            vm.$set(item, 'selected', isSelected);

                            // Sum col8 for items where isNonVisibleInSummary is true
                            if (item.isNonVisibleInSummary === true) {
                                nonVisibleInSummaryCol8Sum += parseFloat(item.col8) || 0;
                            }
                        });

                        // Extract headers and colCount from first line item if available
                        if (vm.lineItemsData.length > 0) {
                            var firstItem = vm.lineItemsData[0];
                            var headerNames = firstItem.headerNames || firstItem.HeaderNames;

                            // Extract ColCount - match MVC: Model.Records.First().ColCount
                            var colCount = firstItem.colCount || firstItem.ColCount;
                            if (colCount !== null && colCount !== undefined) {
                                vm.$set(vm, 'lineItemColCount', colCount);
                            }

                            if (headerNames) {
                                try {
                                    // Parse header names string (format: "  request no -S-TicketNumber-N, type -S-tickettype-N, ...")
                                    // Split by comma to get individual headers
                                    var headersArray = headerNames.split(',');
                                    var parsedHeaders = [];

                                    headersArray.forEach(function (headerStr) {
                                        var trimmed = headerStr.trim();
                                        if (trimmed) {
                                            // Split by dash: [0] = display name, [1] = data type, [2] = column name, [3] = format (optional)
                                            // Handle cases where display name or other parts might contain dashes
                                            var parts = trimmed.split('-');
                                            if (parts.length >= 2) {
                                                // Reconstruct parts properly - handle display names with dashes
                                                var displayName = parts[0].trim();
                                                var dataType = parts[1].trim();
                                                var columnName = '';
                                                var format = 'N';

                                                // If we have more than 2 parts, the last part might be format
                                                // and everything in between is column name
                                                if (parts.length > 2) {
                                                    // Join middle parts as column name (in case it has dashes)
                                                    if (parts.length === 3) {
                                                        columnName = parts[2].trim();
                                                    } else if (parts.length === 4) {
                                                        columnName = parts[2].trim();
                                                        format = parts[3].trim();
                                                    } else if (parts.length > 4) {
                                                        // Column name might contain dashes, join middle parts
                                                        columnName = parts.slice(2, parts.length - 1).join('-').trim();
                                                        format = parts[parts.length - 1].trim();
                                                    }
                                                }

                                                parsedHeaders.push({
                                                    displayName: displayName,
                                                    dataType: dataType,
                                                    columnName: columnName,
                                                    format: format || 'N',
                                                    fullString: trimmed
                                                });
                                            } else {
                                                // If format doesn't match expected pattern, still try to add it
                                                console.warn('Header format unexpected:', trimmed);
                                                parsedHeaders.push({
                                                    displayName: trimmed,
                                                    dataType: '',
                                                    columnName: '',
                                                    format: 'N',
                                                    fullString: trimmed
                                                });
                                            }
                                        }
                                    });

                                    vm.$set(vm, 'lineItemHeaders', parsedHeaders);
                                    console.log('Parsed headers count:', parsedHeaders.length);
                                    console.log('Parsed headers:', parsedHeaders);
                                } catch (e) {
                                    console.warn('Error parsing headers:', e);
                                    console.warn('HeaderNames string:', headerNames);
                                    vm.$set(vm, 'lineItemHeaders', []);
                                }
                            } else {
