        onColumnValueKeydown(event) {
            // Only apply validation for decimal type fields
            if (this.columnValueInputType === "decimal") {
                return this.AllowNumbersWithDotWithNegtaiveValue(event, event.target, true);
            }
            return true;
        },
        AllowNumbersWithDotWithNegtaiveValue(event, element, allowNegative) {
            var charCode = (event.which) ? event.which : event.keyCode;
            var value = $(element).val();

            // Allow: backspace, delete, tab, escape, enter
            if ([8, 9, 27, 13, 46].indexOf(charCode) !== -1 ||
                // Allow: Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+X
                (charCode === 65 && event.ctrlKey === true) ||
                (charCode === 67 && event.ctrlKey === true) ||
                (charCode === 86 && event.ctrlKey === true) ||
                (charCode === 88 && event.ctrlKey === true) ||
                // Allow: home, end, left, right
                (charCode >= 35 && charCode <= 39)) {
                return true;
            }

            // Ensure that it is a number and stop the keypress
            if ((charCode < 48 || charCode > 57) && charCode !== 46 && charCode !== 45) {
                event.preventDefault();
                return false;
            }

            // Allow negative sign only at the beginning
            if (charCode === 45 && allowNegative) {
                if (value.indexOf('-') !== -1 || value.length > 0) {
                    event.preventDefault();
                    return false;
                }
                return true;
            }

            // Allow only one dot
            if (charCode === 46 && value.indexOf('.') !== -1) {
                event.preventDefault();
                return false;
            }

            return true;
        },
