        calculateDiscountAndTax() {

            var vm = this;
            var subtotal = parseFloat(vm.invoiceData.SubTotal) || 0;
            var newSubTotal = subtotal;

            // Calculate discounts
            vm.discountRows.forEach(function (discount) {
                var percentage = parseFloat(discount.percentage) || 0;

                if (vm.invoiceData.DiscountType !== 'Stack') {
                    // For Stack: calculate based on newSubTotal (which decreases after each discount)
                    var discountAmount = (newSubTotal * percentage) / 100;
                    discount.amount = parseFloat(discountAmount.toFixed(2));
                    newSubTotal = newSubTotal - discount.amount;
                } else {
                    // For Sequential: calculate based on original subtotal
                    var discountAmount = (subtotal * percentage) / 100;
                    discount.amount = parseFloat(discountAmount.toFixed(2));
                }
            });

            // Recalculate subtotal by applying all discount amounts with their operators
            var adjustedSubtotal = subtotal;
            vm.discountRows.forEach(function (discount) {
                var discountAmount = parseFloat(discount.amount) || 0;
                if (discountAmount > 0) {
                    // Discount operator is "-" (value is "-")
                    adjustedSubtotal -= discountAmount;
                }
            });

            // Calculate taxes based on the adjusted subtotal (after discounts)
            vm.taxRows.forEach(function (tax) {
                var percentage = parseFloat(tax.percentage) || 0;
                var taxAmount = (adjustedSubtotal * percentage) / 100;
                tax.amount = parseFloat(taxAmount.toFixed(2));
            });

            vm.calculateGrandTotal();
        },

