        calculateGrandTotal() {

            try {
                var vm = this;
                var total = parseFloat(vm.invoiceData.SubTotal) || 0;

                // Apply discounts with their operators
                vm.discountRows.forEach(function (discount) {
                    var discountAmount = parseFloat(discount.amount) || 0;
                    if (discountAmount > 0) {
                        // Discount operator is "-"
                        total -= discountAmount;
                    }
                });

                // Apply taxes with their operators
                vm.taxRows.forEach(function (tax) {
                    var taxAmount = parseFloat(tax.amount) || 0;
                    if (taxAmount > 0) {
                        // Tax operator is "+"
                        total += taxAmount;
                    }
                });

                total = parseFloat(total.toFixed(2));
                vm.invoiceData.BillTotalNoAdv = total.toFixed(2);

                // Calculate BillNetTotal
                var billTotalNoAdv = parseFloat(vm.invoiceData.BillTotalNoAdv) || 0;
                var flatDiscount = parseFloat(vm.invoiceData.DiscountFlatRate) || 0;
                var advance = parseFloat(vm.invoiceData.BillAdvanceAmount) || 0;
                var credit = parseFloat(vm.invoiceData.CreditAmount) || 0;

                var billNetTotal = billTotalNoAdv - flatDiscount - advance - credit;

                if (isNaN(billNetTotal) || !isFinite(billNetTotal)) {
                    vm.invoiceData.BillNetTotal = '0.00';
                } else {
                    var roundedTotal = parseFloat((Math.round(billNetTotal * 100) / 100).toFixed(2));
                    vm.invoiceData.BillNetTotal = roundedTotal.toFixed(2);
                }
            } catch (ex) {
                console.error('Error in calculateGrandTotal:', ex);
            }
        },

        onNoteDeleted(result) {
            var vm = this;
            // Handle note deleted event if needed
            // result contains UniqueName, LatestNote, DivisionId, UtilityId
        },

        onNoteSaved() {
            var vm = this;
            this.refreshKey += 1;
            vm.closeAddNote();
            // Refresh notes count if needed
        },
        closeAdvanceFilter() {
            this.showAdvanceFilter = false;
        },
        closeChangeContract() {
            this.showChangeContract = false;
        },
        onContractChanged() {
            var vm = this;
            vm.closeChangeContract();
            vm.loadLineItems();
        },
        closeManageWorkCode() {
            this.showManageWorkCode = false;
        },
        onSave() {
            debugger
            var vm = this;
            vm.invoiceStatus = 'NotShowNumber';
            var privilegeParams = `controller=ClientInvoice&action=Save`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
                if (true) {
                    // Check invoice status - if NotShowNumber, clear BillNumber
                    if (vm.invoiceStatus === 'NotShowNumber' && (!vm.billId || vm.billId === 0)) {
                        vm.invoiceData.BillNumber = '';
                    }

                    // Validation
                    var msg = '';
                    var validationErrors = {};

                    // Check discount flat rate vs non-visible summary cost
                    if (typeof vm.notInSummaryCost === 'undefined') {
                        vm.notInSummaryCost = 0;
                    }
                    var discountFlatRate = parseFloat(vm.invoiceData.DiscountFlatRate) || 0;
                    var notInSummaryCost = parseFloat(vm.notInSummaryCost) || 0;
                    if (discountFlatRate !== notInSummaryCost && notInSummaryCost > 0) {
                        vm.ShowAlert(vm.$t('DiscountInvoiceALertMessage').replace('{0}', notInSummaryCost.toString()), "warning", vm.$t('Alert'));
                        return false;
                    }

                    // Check if line items exist
                    if (!vm.lineItemsData || vm.lineItemsData.length === 0) {
                        vm.ShowAlert(vm.$t('PleaseAddSomeLineItems'), "warning", vm.$t('Alert'));
                        return false;
                    }

                    // Validate Payment Term
                    if (vm.paymentTermAllowed === 'yes' && (!vm.invoiceData.PaymentTermId || vm.invoiceData.PaymentTermId === '')) {
                        validationErrors.PaymentTermId = vm.$t('Required').replace('{0}', vm.$t('PaymentTerm'));
                        msg += 'no';
                    }

                    // Validate Due Date
                    if (!vm.invoiceData.BillDueDate || vm.invoiceData.BillDueDate === '') {
                        validationErrors.BillDueDate = vm.$t('Required').replace('{0}', vm.$t('DueDate'));
                        msg += 'no';
                    }

                    // Validate Issue Date
                    if (!vm.invoiceData.BillIssueDate || vm.invoiceData.BillIssueDate === '') {
                        validationErrors.BillIssueDate = vm.$t('Required').replace('{0}', vm.$t('BillIssueDate'));
                        msg += 'no';
                    }

                    // Validate dates format
                    if (vm.invoiceData.BillIssueDate) {
                        var issueDate = new Date(vm.invoiceData.BillIssueDate);
                        if (isNaN(issueDate.getTime())) {
                            validationErrors.BillIssueDate = vm.$t('InvalidDatePattern');
                            msg += 'no';
                        }
                    }
                    if (vm.invoiceData.BillDueDate) {
                        var dueDate = new Date(vm.invoiceData.BillDueDate);
                        if (isNaN(dueDate.getTime())) {
                            validationErrors.BillDueDate = vm.$t('InvalidDatePattern');
                            msg += 'no';
                        }
                    }
                    if (vm.invoiceData.DateRangeFrom) {
                        var dateFrom = new Date(vm.invoiceData.DateRangeFrom);
                        if (isNaN(dateFrom.getTime())) {
                            validationErrors.DateRangeFrom = vm.$t('InvalidDatePattern');
                            msg += 'no';
                        }
                    }
                    if (vm.invoiceData.DateRangeTo) {
                        var dateTo = new Date(vm.invoiceData.DateRangeTo);
                        if (isNaN(dateTo.getTime())) {
                            validationErrors.DateRangeTo = vm.$t('InvalidDatePattern');
                            msg += 'no';
                        }
                    }

                    // Validate discount rows (only validate rows that have data)
                    var discountValidationErrors = 0;
                    vm.discountRows.forEach(function (discount, index) {
                        // Skip empty rows (rows without label or percentage)
                        if (!discount.label || discount.label.trim() === '' || !discount.percentage) {
                            return;
                        }
                        // Validate required fields for non-empty rows
                        if (!discount.label || discount.label.trim() === '') {
                            discountValidationErrors++;
                        }
                        if (!discount.percentage || discount.percentage === '') {
                            discountValidationErrors++;
                        }
                        if (discount.amount === undefined || discount.amount === null || discount.amount === '') {
                            discountValidationErrors++;
                        }
                    });

                    // Validate tax rows (only validate rows that have data)
                    var taxValidationErrors = 0;
                    vm.taxRows.forEach(function (tax, index) {
                        // Skip empty rows (rows without label or percentage)
                        if (!tax.label || tax.label.trim() === '' || !tax.percentage) {
                            return;
                        }
                        // Validate required fields for non-empty rows
                        if (!tax.label || tax.label.trim() === '') {
                            taxValidationErrors++;
                        }
                        if (!tax.percentage || tax.percentage === '') {
                            taxValidationErrors++;
                        }
                        if (tax.amount === undefined || tax.amount === null || tax.amount === '') {
                            taxValidationErrors++;
                        }
                    });

                    // Validate Discount Flat Rate
                    if (vm.invoiceData.DiscountFlatRate < 0 || vm.invoiceData.DiscountFlatRate === null || vm.invoiceData.DiscountFlatRate === undefined) {
                        validationErrors.DiscountFlatRate = vm.$t('Required').replace('{0}', vm.$t('DiscountFlatRate'));
                        msg += 'no';
                    }

                    // Validate Advance Amount
                    if (vm.invoiceData.BillAdvanceAmount < 0 || vm.invoiceData.BillAdvanceAmount === null || vm.invoiceData.BillAdvanceAmount === undefined) {
                        validationErrors.BillAdvanceAmount = vm.$t('Required').replace('{0}', vm.$t('AdvanceReceived'));
                        msg += 'no';
                    }

                    // Validate Net Total
                    if (!vm.invoiceData.BillNetTotal || vm.invoiceData.BillNetTotal === '' || vm.invoiceData.BillNetTotal === null) {
                        validationErrors.BillNetTotal = vm.$t('Required').replace('{0}', vm.$t('NetTotal'));
                        msg += 'no';
                    }

                    // Validate Bill Number if needed (when invoiceStatus is ShowNumber)
                    // Note: hdnChekInvoiceNumber equivalent would be checking invoiceStatus
                    if (vm.invoiceStatus === 'ShowNumber' && (!vm.invoiceData.BillNumber || vm.invoiceData.BillNumber === '')) {
                        validationErrors.BillNumber = vm.$t('Required').replace('{0}', vm.$t('BillNumber'));
                        msg += 'no';
                    }

                    // Validate Credit Amount if credit is checked
                    if (vm.invoiceData.IsCredit) {
                        if (!vm.invoiceData.CreditAmount || vm.invoiceData.CreditAmount === '' || vm.invoiceData.CreditAmount === null) {
                            validationErrors.CreditAmount = vm.$t('Required').replace('{0}', vm.$t('Amount'));
                            msg += 'no';
                        }
                    }

                    // Validate Invoice Detail Template if feature is enabled
                    if (vm.isShowInvoiceDetailDropdown) {
                        if (!vm.invoiceData.TemplateId || vm.invoiceData.TemplateId === '' || vm.invoiceData.TemplateId === null) {
                            validationErrors.TemplateId = vm.$t('Required').replace('{0}', vm.$t('InvoiceDetailTemplate'));
                            msg += 'no';
                        }
                        if (!vm.invoiceData.DetailFileFormat || vm.invoiceData.DetailFileFormat === '' || vm.invoiceData.DetailFileFormat === null) {
                            validationErrors.DetailFileFormat = vm.$t('Required').replace('{0}', vm.$t('DetailFileFormat'));
                            msg += 'no';
                        }
                    }

                    // Validate Workday Invoice Type if feature is enabled
                    if (vm.isShowWorkdayInvoiceType) {
                        if (!vm.invoiceData.InvoiceTypeId || vm.invoiceData.InvoiceTypeId === '' || vm.invoiceData.InvoiceTypeId === null) {
                            validationErrors.InvoiceTypeId = vm.$t('Required').replace('{0}', vm.$t('WorkdayInvoiceType'));
                            msg += 'no';
                        }
                    }

                    // Check if filters are active - warn user to remove them
                    if (vm.activeFilters && vm.activeFilters.length > 0) {
                        vm.ShowAlert(vm.$t('InvoiceLineItemRemoveSearchFilter'), "warning", vm.$t('Alert'));
                        return false;
                    }

                    // If validation passed
                    if (discountValidationErrors === 0 && taxValidationErrors === 0 && msg.length === 0) {
                        // Calculate discount and tax totals
                        var discountFlatRateTotal = 0;
                        var billTotalTax = 0;

                        // Calculate discount total from discount rows (skip empty rows)
                        vm.discountRows.forEach(function (discount, index) {
                            // Skip empty rows (rows without label or percentage)
                            if (!discount.label || discount.label.trim() === '' || !discount.percentage) {
                                return;
                            }
                            discountFlatRateTotal += parseFloat(discount.amount || 0);
                        });

                        // Calculate tax total from tax rows (skip empty rows)
                        vm.taxRows.forEach(function (tax, index) {
                            // Skip empty rows (rows without label or percentage)
                            if (!tax.label || tax.label.trim() === '' || !tax.percentage) {
                                return;
                            }
                            billTotalTax += parseFloat(tax.amount || 0);
                        });

                        // Build XML for adjustments
                        var xmlBillAdjustment = "<BILLITEM>\n";

                        // Add discount rows to XML (skip empty rows)
                        vm.discountRows.forEach(function (discount, index) {
                            // Skip empty rows (rows without label or percentage)
                            if (!discount.label || discount.label.trim() === '' || !discount.percentage) {
                                return;
                            }
                            var adjOperator = "0"; // "-" for discount
                            var adjAmount = parseFloat(discount.amount || 0);
                            var adjPercentage = parseFloat(discount.percentage || 0);
                            xmlBillAdjustment += "\n<ITEMRECORD>\n\t<ADJUSTMENT_NAME>" + (discount.label || '') + "</ADJUSTMENT_NAME>" +
                                "\n\t<ADJUSTMENT_OPERATION>" + adjOperator + "</ADJUSTMENT_OPERATION>" +
                                "\n\t<ADJUSTMENT_AMOUNT>" + adjAmount + "</ADJUSTMENT_AMOUNT>" +
                                "\n\t<ADJUSTMENT_PERCENTAGE>" + adjPercentage + "</ADJUSTMENT_PERCENTAGE>" +
                                "\n</ITEMRECORD>\n";
                        });

                        // Add tax rows to XML (skip empty rows)
                        vm.taxRows.forEach(function (tax, index) {
                            // Skip empty rows (rows without label or percentage)
                            if (!tax.label || tax.label.trim() === '' || !tax.percentage) {
                                return;
                            }
                            var adjOperator = "1"; // "+" for tax
                            var adjAmount = parseFloat(tax.amount || 0);
                            var adjPercentage = parseFloat(tax.percentage || 0);
                            xmlBillAdjustment += "\n<ITEMRECORD>\n\t<ADJUSTMENT_NAME>" + (tax.label || '') + "</ADJUSTMENT_NAME>" +
                                "\n\t<ADJUSTMENT_OPERATION>" + adjOperator + "</ADJUSTMENT_OPERATION>" +
                                "\n\t<ADJUSTMENT_AMOUNT>" + adjAmount + "</ADJUSTMENT_AMOUNT>" +
                                "\n\t<ADJUSTMENT_PERCENTAGE>" + adjPercentage + "</ADJUSTMENT_PERCENTAGE>" +
                                "\n</ITEMRECORD>\n";
                        });

                        xmlBillAdjustment += "\n</BILLITEM>\n";


                        var billNumberToSave = vm.invoiceData.BillNumber;

                        if (!vm.billId || vm.billId === 0) {
                            billNumberToSave = (!billNumberToSave || billNumberToSave === '')
                                ? (vm.invoiceData.LatestInvoiceNo || vm.invoiceData.InvoiceStartNo || 'Draft Mode')
                                : billNumberToSave.trim();
                        }


                        // Build data object
                        var saveData = {
                            ClientId: vm.invoiceData.ClientId || vm.searchData.ClientId,
                            BatchId: vm.batchId || '',
                            DateFrom: vm.searchData.dateFrom || '',
                            DateTo: vm.searchData.dateTo || '',
                            LineItems: null,
                            BillIssueDate: vm.invoiceData.BillIssueDate || '',
                            BillNumber: billNumberToSave,
                            BillDueDate: vm.invoiceData.BillDueDate || '',
                            SetupId: vm.setupId || '',
                            XmlStr: xmlBillAdjustment,
                            SubTotal: vm.invoiceData.SubTotal || 0,
                            BillTotalDiscount: discountFlatRateTotal,
                            BillTotalTax: billTotalTax,
                            BillTotalNoAdv: vm.invoiceData.BillTotalNoAdv || 0,
                            BillAdvanceAmount: vm.invoiceData.BillAdvanceAmount || 0,
                            BillDateComments: vm.invoiceData.BillDateComments || '',
                            Terms: vm.invoiceData.Terms || '',
                            BillDescription: vm.invoiceData.Comment || '',
                            BillNetTotal: vm.invoiceData.BillNetTotal || 0,
                            DiscountFlatRate: vm.invoiceData.DiscountFlatRate || 0,
                            DiscountType: vm.invoiceData.DiscountType || 'Sequential',
                            Frequency: '',
                            CustomFrequencyDate: '',
                            Adjustments: null,
                            DisplayStatus: null,
                            ItemQty: null,
                            StatusCode: null,
                            BillDateFrom: null,
                            BillDateTo: null,
                            BillDate_From: null,
                            BillDate_To: null,
                            PONumber: null,
                            PaidAmount: null,
                            ClientName: null,
                            LatestInvoiceNo: null,
                            InvoiceStartNo: null,
                            CreditAmount: vm.invoiceData.IsCredit ? (vm.invoiceData.CreditAmount || null) : null,
                            IsCredit: vm.invoiceData.IsCredit ? 1 : 0,
                            UpdateBillId: vm.billId || 0,
                            TemplateId: vm.invoiceData.TemplateId || vm.templateId || '',
                            ParentCompanyId: vm.invoiceData.ParentCompanyId || '',
                            PaymentTermId: vm.invoiceData.PaymentTermId || null,
                            DateRangeFrom: vm.invoiceData.DateRangeFrom || '',
                            DateRangeTo: vm.invoiceData.DateRangeTo || '',
                            BACId: null,
                            InvoiceTypeId: vm.invoiceData.InvoiceTypeId || null,
                            divisionId: vm.invoiceData.DivisionId || vm.searchData.DivisionId,
                            InvoiceMemo: vm.invoiceData.InvoiceMemo || '',
                            InvoicePONumber: vm.invoiceData.InvoicePONumber || '',
                            ProjectId: vm.invoiceData.ProjectId || "",
                            DetailFileFormat: vm.invoiceData.DetailFileFormat || null,
                            LineBatchId: vm.lineBatchId || ''
                        };

                        const postData = {
                            postString: JSON.stringify(saveData)
                        };

                        // Show loader and save
                        vm.isLoading = true;
                        locateBillingService.SaveInvoice(postData).then(function (response) {
                            vm.isLoading = false;
                            if (response && response.data) {
                                if (response.data !== null) {
                                    var successMessage = '';
                                    if (vm.billId > 0) {
                                        successMessage = vm.$t('UpdatedSuccess').replace('{0}', vm.$t('Invoice'));
                                    } else {
                                        var invoiceNumber = response.data.invoiceNumber || '';
                                        successMessage = vm.$t('SubmitSuccess')
                                            .replace('{0}', vm.$t('Invoice'))
                                            .replace('{1}', vm.$t('Generated').toLowerCase())
                                            .replace('{2}', invoiceNumber);
                                    }
                                    vm.ShowAlert(successMessage, "success", vm.$t('Alert'));
                                    setTimeout(function () {
                                        window.location.href = '/ClientBill/Index';
                                    }, 200);
                                } else if (response.data.status === "-1" || response.data.status === -1) {
                                    vm.ShowAlert(vm.$t('Duplicateinvoicenumber'), "failure", vm.$t('Alert'));
                                } else {
                                    vm.ShowAlert(vm.$t('AddedError').replace('{0}', vm.$t('Invoice')), "failure", vm.$t('Alert'));
                                }
                            } else {
                                vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                            }
                        }).catch(function (error) {
                            vm.isLoading = false;
                            console.log('Error saving invoice:', error);
                            vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                        });
                    } else {
                        // Show validation errors
                        vm.ShowAlert(vm.$t('CorrectHighlightedErrors'), "warning", vm.$t('Alert'));
                    }
                } else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
            });
        },
        closeAddDiscount() {
            this.showAddDiscount = false;
            this.selectedDiscountItemId = null;
            this.selectedDiscountItemCost = 0;
        },
        onDiscountSaving() {
            this.isLoading = true;
        },
        onDiscountSaved(data) {

            var vm = this;
            // Update the line item discount in the list immediately for UI update
            var item = vm.lineItemsData.find(function (i) {
                var itemId = i.lineItemId || i.LineItemId;
                return itemId == data.itemId || itemId === data.itemId;
            });
            if (item) {
                var discountValue = parseFloat(data.discount) || 0;
                // Set discount value (matching MVC: $(".aAddDiscount[data-itemid=" + itemId + "]").text(discount))
                vm.$set(item, 'discount', discountValue);

                // Update global tracking variables (matching MVC behavior)
                if (vm.hdnGlobalCurrentID != data.itemId) {
                    vm.hdnGlobalCurrentID = data.itemId;
                    vm.hdnGlobalTotal = parseFloat(vm.invoiceData.SubTotal) || 0;
                }

                // Update subtotal by subtracting discount (matching MVC: actualsubtotal = hdnGlobalTotal - discount)
                var actualSubTotal = parseFloat(vm.hdnGlobalTotal) - discountValue;
                vm.$set(vm.invoiceData, 'SubTotal', actualSubTotal.toFixed(2));

                // Remove 'add' class and show delete button (matching MVC jQuery behavior)
                // This is handled by the LineItems component based on discount > 0
            }

            // Reload line items to get updated data with correct subtotal from server
            vm.loadLineItems().then(function () {
                // Recalculate totals after reloading (similar to jQuery CalculateDiscountAndTax and CalculateGrandTotal)
                vm.$nextTick(function () {
                    vm.calculateDiscountAndTax();
                    vm.calculateGrandTotal();
                });
            }).catch(function (error) {
                console.log('Error reloading line items after discount save:', error);
                // Still recalculate even if reload fails
                vm.$nextTick(function () {
                    vm.calculateDiscountAndTax();
                    vm.calculateGrandTotal();
                });
            });
        },
        onDiscountSavedComplete() {
            this.isLoading = false;
            this.closeAddDiscount();
        },

    }
}

</script>

